                Regex regexMerchantID = new Regex(@"^[a-zA-Z0-9]+$", RegexOptions.CultureInvariant);
                if (!regexMerchantID.Match(this.MerchantID).Success)
                {
                    yield return new System.ComponentModel.DataAnnotations.ValidationResult("Invalid value for MerchantID, must match a pattern of " + regexMerchantID, new [] { "MerchantID" });
                }
            }

            // StartingValue (int) minimum
            if (this.StartingValue < (int)0)
            {
                yield return new ValidationResult("Invalid value for StartingValue, must be a value greater than or equal to 0.", new [] { "StartingValue" });
            }

            // MaxBudget (int) minimum
            if (this.MaxBudget < (int)0)
            {
                yield return new ValidationResult("Invalid value for MaxBudget, must be a value greater than or equal to 0.", new [] { "MaxBudget" });
            }

            // TemporalDecreaseAmount (int) minimum
            if (this.TemporalDecreaseAmount < (int)0)
            {
                yield return new ValidationResult("Invalid value for TemporalDecreaseAmount, must be a value greater than or equal to 0.", new [] { "TemporalDecreaseAmount" });
            }

            // TemporalDecreaseFrequency (int) minimum
            if (this.TemporalDecreaseFrequency < (int)0)
            {
                yield return new ValidationResult("Invalid value for TemporalDecreaseFrequency, must be a value greater than or equal to 0.", new [] { "TemporalDecreaseFrequency" });
            }

            // NumericalDecreaseAmount (int) minimum
            if (this.NumericalDecreaseAmount < (int)0)
            {
                yield return new ValidationResult("Invalid value for NumericalDecreaseAmount, must be a value greater than or equal to 0.", new [] { "NumericalDecreaseAmount" });
            }

            // NumericalDecreaseFrequency (int) minimum
            if (this.NumericalDecreaseFrequency < (int)0)
            {
                yield return new ValidationResult("Invalid value for NumericalDecreaseFrequency, must be a value greater than or equal to 0.", new [] { "NumericalDecreaseFrequency" });
            }

            yield break;
        }
    }

}
